import{_ as a,o as e,c as l,a3 as r}from"./chunks/framework.BTFg6ESq.js";const b=JSON.parse('{"title":"📎 附件与资产","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/attachments.md","filePath":"user-guide/tools/llm-chat/attachments.md","lastUpdated":1778221347000}'),d={name:"user-guide/tools/llm-chat/attachments.md"};function o(i,t,h,n,s,c){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="📎-附件与资产" tabindex="-1">📎 附件与资产 <a class="header-anchor" href="#📎-附件与资产" aria-label="Permalink to &quot;📎 附件与资产&quot;">​</a></h1><p>LLM Chat 支持将图片、音频、视频、文档等文件作为附件随消息一起发送，并深度集成资产管理器和多模态转写系统。</p><h2 id="支持的附件类型" tabindex="-1">支持的附件类型 <a class="header-anchor" href="#支持的附件类型" aria-label="Permalink to &quot;支持的附件类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>格式</th><th>说明</th></tr></thead><tbody><tr><td>📷 图片</td><td>PNG, JPG, GIF, WebP, SVG, BMP</td><td>自动生成缩略图预览，支持拖拽排序</td></tr><tr><td>🎵 音频</td><td>MP3, WAV, OGG, M4A, AAC, FLAC</td><td>自动转写为文本（需启用转写功能）</td></tr><tr><td>🎬 视频</td><td>MP4, AVI, MOV, MKV, WebM</td><td>自动压缩和转写</td></tr><tr><td>📄 文档</td><td>PDF, TXT, DOCX, MD, CSV, JSON</td><td>PDF 自动转写，纯文本直接插入</td></tr><tr><td>📁 其他</td><td>任何文件</td><td>作为文件引用发送</td></tr></tbody></table><h2 id="添加附件" tabindex="-1">添加附件 <a class="header-anchor" href="#添加附件" aria-label="Permalink to &quot;添加附件&quot;">​</a></h2><h3 id="方法一-点击按钮" tabindex="-1">方法一：点击按钮 <a class="header-anchor" href="#方法一-点击按钮" aria-label="Permalink to &quot;方法一：点击按钮&quot;">​</a></h3><ol><li>在输入框上方找到 📎 按钮</li><li>点击打开文件选择器</li><li>选择一个或多个文件</li><li>文件会立即显示为预览卡片，后台异步导入</li></ol><h3 id="方法二-拖拽上传" tabindex="-1">方法二：拖拽上传 <a class="header-anchor" href="#方法二-拖拽上传" aria-label="Permalink to &quot;方法二：拖拽上传&quot;">​</a></h3><p>直接将文件从文件管理器拖拽到对话区域或输入框上方的拖放区域即可。</p><h3 id="方法三-粘贴" tabindex="-1">方法三：粘贴 <a class="header-anchor" href="#方法三-粘贴" aria-label="Permalink to &quot;方法三：粘贴&quot;">​</a></h3><p>从剪贴板复制图片等文件，在输入框中粘贴即可自动添加。</p><h3 id="方法四-从资产管理器" tabindex="-1">方法四：从资产管理器 <a class="header-anchor" href="#方法四-从资产管理器" aria-label="Permalink to &quot;方法四：从资产管理器&quot;">​</a></h3><p>在资产管理器中选择文件，点击「发送到 LLM Chat」按钮。</p><h2 id="附件处理流程" tabindex="-1">附件处理流程 <a class="header-anchor" href="#附件处理流程" aria-label="Permalink to &quot;附件处理流程&quot;">​</a></h2><p>为了保证丝滑的操作体验，LLM Chat 采用了<strong>非阻塞异步处理</strong>架构：</p><ol><li><strong>瞬时预览</strong>：添加文件后，UI 会立即显示预览卡片，不会因为文件大而卡顿。</li><li><strong>后台静默导入</strong>：系统在后台自动完成文件复制、SHA256 去重和缩略图生成。</li><li><strong>智能能力感知</strong>：系统会自动识别当前所选模型的能力（如是否支持 Vision、音频或长文档）。 <ul><li>如果模型不支持，卡片会显示警告，提示你切换模型或开启转写。</li></ul></li><li><strong>自动引用转换</strong>：发送消息时，系统会自动将文件转换为模型可理解的 Base64 或云端 URL。</li></ol><h3 id="导入状态指示" tabindex="-1">导入状态指示 <a class="header-anchor" href="#导入状态指示" aria-label="Permalink to &quot;导入状态指示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>指示</th><th>说明</th></tr></thead><tbody><tr><td>⏳ 等待中</td><td>灰色边框</td><td>正在排队等待导入</td></tr><tr><td>🔄 导入中</td><td>旋转动画</td><td>正在文件复制和缩略图生成</td></tr><tr><td>✅ 完成</td><td>正常显示</td><td>导入成功，已就绪</td></tr><tr><td>❌ 失败</td><td>红色边框</td><td>导入出错，可尝试重新添加</td></tr></tbody></table><h2 id="多模态转写" tabindex="-1">多模态转写 <a class="header-anchor" href="#多模态转写" aria-label="Permalink to &quot;多模态转写&quot;">​</a></h2><p>如果当前模型不支持某个附件类型，系统会自动利用你的 AI 服务进行<strong>转写</strong>——将图片/音频/视频/文档的内容提取为文本，然后再发送给模型。</p><h3 id="转写策略" tabindex="-1">转写策略 <a class="header-anchor" href="#转写策略" aria-label="Permalink to &quot;转写策略&quot;">​</a></h3><ul><li><strong>智能模式（默认）</strong>：模型原生支持该类型就直接发送文件，不支持则自动转写</li><li><strong>总是转写</strong>：无论模型是否支持，都强制转写所有附件</li></ul><h3 id="转写配置" tabindex="-1">转写配置 <a class="header-anchor" href="#转写配置" aria-label="Permalink to &quot;转写配置&quot;">​</a></h3><p>在聊天设置 → 附件转写中可以详细配置：</p><ul><li>为不同附件类型指定专门的转写模型</li><li>自定义转写 Prompt</li><li>控制转写的精细度（温度、最大 Token）</li><li>配置视频/音频压缩参数（需要 FFmpeg）</li></ul><blockquote><p>TODO: 截图 — 附件预览卡片和转写设置</p></blockquote><h2 id="管理附件" tabindex="-1">管理附件 <a class="header-anchor" href="#管理附件" aria-label="Permalink to &quot;管理附件&quot;">​</a></h2><p>添加附件后，你可以：</p><ul><li><strong>查看预览</strong>：图片显示缩略图，音频显示播放器</li><li><strong>移除附件</strong>：点击附件卡片上的 ✕ 按钮</li><li><strong>拖拽排序</strong>：调整多附件时的顺序</li><li><strong>查看提示</strong>：如果模型不支持该类型，卡片上会显示警告信息</li></ul><h2 id="与资产管理器的集成" tabindex="-1">与资产管理器的集成 <a class="header-anchor" href="#与资产管理器的集成" aria-label="Permalink to &quot;与资产管理器的集成&quot;">​</a></h2><p>所有添加的附件都会通过资产管理系统的导入管道处理。导入成功的文件会进入资产管理器的索引，你可以在资产管理器中对它们进行：</p><ul><li>浏览和管理历史附件</li><li>按来源模块筛选</li><li>批量操作（删除、导出）</li></ul><h2 id="输入框中的附件占位符" tabindex="-1">输入框中的附件占位符 <a class="header-anchor" href="#输入框中的附件占位符" aria-label="Permalink to &quot;输入框中的附件占位符&quot;">​</a></h2><p>当你发送包含附件的消息时，系统会在消息文本中插入类似 <code>【file::assetId::文件名】</code> 的占位符。上下文管道中的 <code>Asset Resolver</code> 处理器会在发送前将这些占位符解析为模型能够理解的文件引用或内容。</p><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="./../../tools/asset-manager/index">资产管理器</a> — 完整资产管理使用指南</li><li><a href="./settings-chat">聊天参数 — 附件转写</a> — 转写的详细配置</li></ul>',36)])])}const p=a(d,[["render",o]]);export{b as __pageData,p as default};
